sql:
SELECT title
FROM problems
WHERE acceptance_rate = (SELECT MAX(acceptance_rate) FROM problems);

SELECT COUNT(DISTINCT user_id) AS number_of_users_solved_problems
FROM submissions
WHERE status = 'Accepted';

SELECT title, acceptance_rate
FROM problems
ORDER BY acceptance_rate DESC;

external_knowledge:
- "easier problems" refers to problems with an acceptance rate greater than 70%.;
- "average solving times" refers to the average time taken to solve problems across different difficulty levels.;
- "most people seem to solve quite successfully" refers to a high acceptance rate.

sql:
SELECT AVG(solving_time) AS average_solving_time
FROM problems
WHERE difficulty = 'Easy';

SELECT COUNT(DISTINCT user_id) AS user_count
FROM submissions
WHERE problem_id = 1 AND status = 'Accepted';

SELECT AVG(solving_time) AS average_solving_time
FROM problems
WHERE difficulty = 'Medium';

external_knowledge:
- "active members" refers to users who received notifications;
- "typical performance" corresponds to the average score;
- "more than a couple of updates" means more than two notifications;
- "April" refers to the date range between '2023-04-01' and '2023-04-30'.

sql:
SELECT problem_id
FROM problems
WHERE solving_time > (
    SELECT AVG(solving_time)
    FROM problems
);
